#include <iostream>
#include <string>
#include <sstream>
#include <vector>
#include <limits>

// This function simulates running the user's main function
// It assumes the user's main function is compiled into an executable
// and this driver provides the input and captures the output.
std::string run_user_code(const std::string& input_str) {
    std::stringstream ss_in(input_str);
    std::stringstream ss_out;

    // Save original cin/cout/cerr buffers
    std::streambuf* old_cin = std::cin.rdbuf();
    std::streambuf* old_cout = std::cout.rdbuf();
    std::streambuf* old_cerr = std::cerr.rdbuf();

    // Redirect cin/cout/cerr to stringstreams
    std::cin.rdbuf(ss_in.rdbuf());
    std::cout.rdbuf(ss_out.rdbuf());
    std::cerr.rdbuf(ss_out.rdbuf()); 

    // Call the user's main function. 
    // This typically requires renaming the user's main to avoid conflicts,
    // e.g., 'user_main_solution()', or running as a separate process.
    // For this template, we assume the test harness executes the user's main
    // after setting up the redirection.
    // The actual execution of `main` is handled by the test infrastructure.

    // Restore original cin/cout/cerr buffers (important for subsequent tests)
    std::cin.rdbuf(old_cin);
    std::cout.rdbuf(old_cout);
    std::cerr.rdbuf(old_cerr);

    return ss_out.str();
}
